from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk
import logging

# Connect to Elasticsearch cluster
es = Elasticsearch('localhost:9200')

# Index documents
def index_documents(index_name, documents):
    actions = [
        {'_index': index_name, **doc}
        for doc in documents
    ]
    bulk(es, actions)

# Perform search queries
def search_query(index_name, query):
    result = es.search(index=index_name, body={'query': {'match': {'message': query}}})
    return result['hits']['hits']

# Log aggregation
def log_aggregation(index_name, aggregation_query):
    result = es.search(index=index_name, body=aggregation_query)
    return result['aggregations']

